// ===== EDIT YOUR SETTINGS HERE =====
// Defaults below match the Gumroad + n8n Creator listings.
// Change only what you need; leave unused destinations as placeholders.

// Where to log quotes:
//   'airtable' → Airtable only
//   'sheets'   → Google Sheets only
//   'both'     → Airtable and Google Sheets
const QUOTE_LOG = 'airtable';

const AIRTABLE_BASE_ID = 'appXXXXXXXXXXXXXX';
const QUOTES_TABLE_NAME = 'Quotes';

// Required when QUOTE_LOG is 'sheets' or 'both'
const GOOGLE_SHEET_ID = 'your-google-sheet-id';
const SHEETS_TAB_NAME = 'Quotes';

// Where to send chat alerts for hot/warm leads:
//   'teams'  → Microsoft Teams only
//   'slack'  → Slack only
//   'both'   → Teams and Slack
const NOTIFY_CHANNELS = 'teams';

// Microsoft Teams incoming webhook URL (Channel → Connectors → Incoming Webhook)
// Required when NOTIFY_CHANNELS is 'teams' or 'both'
const TEAMS_WEBHOOK_URL = 'https://outlook.office.com/webhook/your-teams-incoming-webhook';

// Slack channel name (with #). Required when NOTIFY_CHANNELS is 'slack' or 'both'
const SLACK_CHANNEL = '#quote-leads';

// Twilio SMS — hot leads only
const TWILIO_FROM_NUMBER = '+1234567890';
const AGENT_MOBILE_NUMBER = '+1234567890';

// Lead score at or above this value triggers SMS + priority chat alerts
const HOT_LEAD_SCORE_THRESHOLD = 75;

// Skip duplicate submissions with same email/phone within this window (hours)
const DUPLICATE_WINDOW_HOURS = 24;

const DEFAULT_LEAD_SOURCE = 'website_form';

const payload = $input.first().json.body || $input.first().json;
const quoteLog = String(QUOTE_LOG || 'airtable').toLowerCase().trim();
const useAirtableLog = quoteLog === 'airtable' || quoteLog === 'both';
const useSheetsLog = quoteLog === 'sheets' || quoteLog === 'both';

return [
  {
    json: {
      quoteLog,
      useAirtableLog,
      useSheetsLog,
      airtableBaseId: AIRTABLE_BASE_ID,
      quotesTableName: QUOTES_TABLE_NAME,
      googleSheetId: GOOGLE_SHEET_ID,
      sheetsTabName: SHEETS_TAB_NAME,
      notifyChannels: NOTIFY_CHANNELS,
      teamsWebhookUrl: TEAMS_WEBHOOK_URL,
      slackChannel: SLACK_CHANNEL,
      twilioFromNumber: TWILIO_FROM_NUMBER,
      agentMobileNumber: AGENT_MOBILE_NUMBER,
      hotLeadScoreThreshold: HOT_LEAD_SCORE_THRESHOLD,
      duplicateWindowHours: DUPLICATE_WINDOW_HOURS,
      defaultLeadSource: DEFAULT_LEAD_SOURCE,
      payload,
    },
  },
];

const settings = $input.first().json;
const raw = settings.payload || settings.body || settings;

const get = (...keys) => {
  for (const key of keys) {
    if (raw[key] !== undefined && raw[key] !== null && String(raw[key]).trim() !== '') {
      return String(raw[key]).trim();
    }
  }
  return '';
};

const formResponse = raw.form_response || raw;
const answers = formResponse.answers || raw.answers || [];

const answerMap = {};
for (const answer of answers) {
  const field =
    answer.field?.ref ||
    answer.field?.id ||
    answer.title ||
    answer.field?.title ||
    '';
  const key = String(field).toLowerCase();
  let value = '';
  if (answer.text) value = answer.text;
  else if (answer.email) value = answer.email;
  else if (answer.phone_number) value = answer.phone_number;
  else if (answer.choice?.label) value = answer.choice.label;
  else if (answer.choices?.labels) value = answer.choices.labels.join(', ');
  else if (answer.number !== undefined) value = String(answer.number);
  else if (answer.date) value = answer.date;
  else if (answer.boolean !== undefined) value = answer.boolean ? 'yes' : 'no';
  if (key && value) answerMap[key] = value;
}

const fromMap = (...aliases) => {
  for (const alias of aliases) {
    const hit = answerMap[String(alias).toLowerCase()];
    if (hit) return hit;
  }
  return '';
};

const submissionId =
  raw.submission_id ||
  raw.submissionID ||
  formResponse.token ||
  raw.event_id ||
  raw.id ||
  `webhook-${Date.now()}`;

const receivedAt = raw.submitted_at || raw.created_at || new Date().toISOString();

const fullName =
  get('fullName', 'full_name', 'name', 'contact_name') ||
  fromMap('full_name', 'name', 'contact_name', 'your_name') ||
  [get('firstName', 'first_name'), get('lastName', 'last_name')].filter(Boolean).join(' ').trim();

const email =
  get('email', 'contact_email', 'business_email') ||
  fromMap('email', 'contact_email', 'business_email', 'work_email');

const phone =
  get('phone', 'phone_number', 'mobile', 'contact_phone') ||
  fromMap('phone', 'phone_number', 'mobile', 'contact_phone', 'cell_phone');

const businessName =
  get('businessName', 'business_name', 'company', 'company_name') ||
  fromMap('business_name', 'company', 'company_name', 'organization');

const coverageType =
  get('coverageType', 'coverage_type', 'insurance_type', 'policy_type') ||
  fromMap('coverage_type', 'insurance_type', 'policy_type', 'what_coverage_do_you_need');

const industry =
  get('industry', 'business_type', 'sector') ||
  fromMap('industry', 'business_type', 'sector', 'what_industry_are_you_in');

const annualRevenue =
  get('annualRevenue', 'annual_revenue', 'revenue') ||
  fromMap('annual_revenue', 'revenue', 'estimated_annual_revenue');

const employeeCount =
  get('employeeCount', 'employee_count', 'employees') ||
  fromMap('employee_count', 'employees', 'number_of_employees');

const claimsHistory =
  get('claimsHistory', 'claims_history', 'prior_claims') ||
  fromMap('claims_history', 'prior_claims', 'claims_in_last_5_years');

const effectiveDate =
  get('effectiveDate', 'effective_date', 'coverage_start') ||
  fromMap('effective_date', 'coverage_start', 'when_do_you_need_coverage');

const notes =
  get('notes', 'additional_info', 'message', 'details') ||
  fromMap('notes', 'additional_info', 'message', 'anything_else_we_should_know');

const source = get('source', 'lead_source') || fromMap('source', 'lead_source') || settings.defaultLeadSource || 'website_form';

const quoteHash = `${email}|${phone}|${coverageType}|${businessName}`.toLowerCase();

return [
  {
    json: {
      quoteLog: settings.quoteLog,
      useAirtableLog: settings.useAirtableLog,
      useSheetsLog: settings.useSheetsLog,
      airtableBaseId: settings.airtableBaseId,
      quotesTableName: settings.quotesTableName,
      googleSheetId: settings.googleSheetId,
      sheetsTabName: settings.sheetsTabName,
      notifyChannels: settings.notifyChannels,
      teamsWebhookUrl: settings.teamsWebhookUrl,
      slackChannel: settings.slackChannel,
      twilioFromNumber: settings.twilioFromNumber,
      agentMobileNumber: settings.agentMobileNumber,
      hotLeadScoreThreshold: settings.hotLeadScoreThreshold,
      duplicateWindowHours: settings.duplicateWindowHours,
      defaultLeadSource: settings.defaultLeadSource,
      submissionId,
      receivedAt,
      fullName,
      email,
      phone,
      businessName,
      coverageType,
      industry,
      annualRevenue,
      employeeCount,
      claimsHistory,
      effectiveDate,
      notes,
      source,
      quoteHash,
      rawPayload: JSON.stringify(raw).slice(0, 4000),
      _mockExistingQuotes: Array.isArray(raw._mockExistingQuotes) ? raw._mockExistingQuotes : [],
      _testScenario: raw._testScenario || '',
    },
  },
];

const quote = $('Normalize Quote Data').first().json;
const rows = $input
  .all()
  .map((item) => item.json)
  .filter((row) => !row._mockEmpty)
  .map((row) => row.fields || row);

return [{ json: { ...quote, _lookupRows: rows } }];

function fromNode(name) {
  try {
    return $(name).first().json;
  } catch (error) {
    return null;
  }
}

const prev =
  fromNode('Create Airtable Lookup Bundle') ||
  fromNode('Skip Airtable Bundle Creation') ||
  $('Normalize Quote Data').first().json;

const sheetRows = $input
  .all()
  .map((item) => item.json)
  .filter((row) => !row._mockEmpty)
  .map((row) => row.fields || row);

return [
  {
    json: {
      ...prev,
      _lookupRows: [...(prev._lookupRows || []), ...sheetRows],
    },
  },
];

const quote = $input.first().json;
const rows = Array.isArray(quote._lookupRows) ? quote._lookupRows : [];
const windowHours = quote.duplicateWindowHours ?? 24;
const cutoff = Date.now() - windowHours * 60 * 60 * 1000;

const isDuplicate = rows.some((row) => {
  const record = row.fields || row;
  if (record._mockEmpty) return false;
  const existingEmail = (record.Email || record.email || '').toLowerCase();
  const existingPhone = String(record.Phone || record.phone || '').replace(/\D/g, '');
  const existingHash = (record['Quote Hash'] || record.quoteHash || '').toLowerCase();
  const existingAt = Date.parse(record['Received At'] || record.receivedAt || record.createdTime || '');

  if (quote.email && existingEmail && quote.email.toLowerCase() === existingEmail) {
    if (!existingAt || existingAt >= cutoff) return true;
  }

  const phoneDigits = String(quote.phone || '').replace(/\D/g, '');
  if (phoneDigits.length >= 10 && existingPhone && phoneDigits === existingPhone) {
    if (!existingAt || existingAt >= cutoff) return true;
  }

  if (quote.quoteHash && existingHash && quote.quoteHash === existingHash) {
    if (!existingAt || existingAt >= cutoff) return true;
  }

  return false;
});

return [
  {
    json: {
      ...quote,
      isDuplicate,
    },
  },
];

