const quote = $('Check for Duplicate Quote').first().json;
const aiItem = $input.first().json;

const raw =
  aiItem.message?.content ||
  aiItem.text ||
  aiItem.output ||
  aiItem.choices?.[0]?.message?.content ||
  '';

let analysis = {
  leadScore: 50,
  priority: 'warm',
  coverageSummary: 'Quote request received',
  recommendedProducts: [],
  underwritingFlags: [],
  missingInfo: [],
  nextStep: 'Contact prospect within 1 business day',
  talkingPoints: [],
};

try {
  const jsonMatch = String(raw).match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = { ...analysis, ...JSON.parse(jsonMatch[0]) };
  }
} catch (error) {
  analysis.coverageSummary = String(raw).slice(0, 500) || analysis.coverageSummary;
}

const toList = (value) => {
  if (Array.isArray(value)) return value.map((item) => String(item).trim()).filter(Boolean);
  return String(value || '')
    .split('\n')
    .map((item) => item.trim())
    .filter(Boolean);
};

analysis.recommendedProducts = toList(analysis.recommendedProducts);
analysis.underwritingFlags = toList(analysis.underwritingFlags);
analysis.missingInfo = toList(analysis.missingInfo);
analysis.talkingPoints = toList(analysis.talkingPoints);

const score = Math.max(0, Math.min(100, Number(analysis.leadScore) || 50));
const threshold = quote.hotLeadScoreThreshold ?? 75;

let route = 'warm';
let notifyTeams = true;
let notifySms = false;

if (score >= threshold || analysis.priority === 'hot') {
  route = 'hot';
  notifyTeams = true;
  notifySms = true;
} else if (score < 40 || analysis.priority === 'cold') {
  route = 'cold';
  notifyTeams = false;
  notifySms = false;
}

const flagsFormatted = analysis.underwritingFlags.join(' | ') || 'None flagged';
const productsFormatted = analysis.recommendedProducts.join(', ') || 'General commercial lines';
const missingFormatted = analysis.missingInfo.join(' | ') || 'None';

return [
  {
    json: {
      ...quote,
      leadScore: score,
      priority: analysis.priority || route,
      coverageSummary: analysis.coverageSummary,
      recommendedProducts: productsFormatted,
      underwritingFlags: flagsFormatted,
      missingInfo: missingFormatted,
      nextStep: analysis.nextStep,
      talkingPoints: analysis.talkingPoints.join(' | '),
      route,
      notifyTeams,
      notifySms,
    },
  },
];

const item = $input.first().json;

const channels = String(item.notifyChannels || 'teams')
  .toLowerCase()
  .split(',')
  .map((value) => value.trim())
  .filter(Boolean);

const useTeams = item.notifyTeams && (channels.includes('teams') || channels.includes('both'));
const useSlack = item.notifyTeams && (channels.includes('slack') || channels.includes('both'));

const routeEmoji = {
  hot: '🔥',
  warm: '📋',
  cold: '📝',
};

const emoji = routeEmoji[item.route] || '📋';
const headline =
  item.route === 'hot'
    ? 'Hot insurance quote lead'
    : item.route === 'warm'
      ? 'New insurance quote request'
      : 'Quote logged (no alert)';

const details = [
  `Lead score: ${item.leadScore}/100 (${item.route})`,
  `Name: ${item.fullName || 'Not provided'}`,
  `Business: ${item.businessName || 'Not provided'}`,
  `Email: ${item.email || 'Not provided'}`,
  `Phone: ${item.phone || 'Not provided'}`,
  `Coverage requested: ${item.coverageType || 'Not specified'}`,
  `Industry: ${item.industry || 'Not specified'}`,
  `Revenue: ${item.annualRevenue || 'Not provided'}`,
  `Employees: ${item.employeeCount || 'Not provided'}`,
  `Claims history: ${item.claimsHistory || 'Not provided'}`,
  `Effective date: ${item.effectiveDate || 'Not provided'}`,
  `Source: ${item.source}`,
  `AI summary: ${item.coverageSummary}`,
  `Recommended products: ${item.recommendedProducts}`,
  `Underwriting flags: ${item.underwritingFlags}`,
  `Missing info: ${item.missingInfo}`,
  `Next step: ${item.nextStep}`,
  `Talking points: ${item.talkingPoints || 'None'}`,
  item.notes ? `Notes: ${item.notes}` : '',
].filter(Boolean);

const teamsMessage = [
  `${emoji} **${headline}**`,
  '',
  ...details.map((line) => {
    const [label, ...rest] = line.split(':');
    return `**${label}:**${rest.join(':')}`;
  }),
].join('\n');

const slackMessage = [
  `${emoji} *${headline}*`,
  '',
  ...details.map((line) => {
    const [label, ...rest] = line.split(':');
    return `*${label}:*${rest.join(':')}`;
  }),
].join('\n');

return [
  {
    json: {
      ...item,
      useTeams,
      useSlack,
      teamsMessage,
      slackMessage,
      teamsWebhookUrl: item.teamsWebhookUrl,
      slackChannel: item.slackChannel,
    },
  },
];

const item = $input.first().json;

const text = [
  `HOT LEAD (${item.leadScore}/100)`,
  item.fullName || 'Unknown contact',
  item.businessName || 'Unknown business',
  item.coverageType || 'Coverage TBD',
  item.phone || 'No phone',
  `Flags: ${item.underwritingFlags}`,
].join(' | ');

return [
  {
    json: {
      ...item,
      smsBody: text.slice(0, 320),
      smsTo: item.agentMobileNumber,
      smsFrom: item.twilioFromNumber,
    },
  },
];

const prior = $('Record Quote Log').first().json;
const item = $input.first().json;
return [{ json: { ...prior, airtableLogged: 'yes', airtableMocked: false, airtableRecordId: item.id || `recLocal${Date.now()}` } }];
